or:#ebebeb"><p class="cky-empty-cookies-text">No cookies to display.</p></div> </div> </div> </div></div><div class="cky-footer-wrapper"> <span class="cky-footer-shadow"></span> <div class="cky-prefrence-btn-wrapper" data-cky-tag="detail-buttons">  <button class="cky-btn cky-btn-preferences" aria-label="Save My Preferences" data-cky-tag="detail-save-button" style="color:#1863DC;background-color:transparent;border-color:#1863DC"> Save My Preferences </button> <button class="cky-btn cky-btn-accept" aria-label="Concordo" data-cky-tag="detail-accept-button" style="color:#FFFFFF;background-color:#1863DC;border-color:#1863DC"> Concordo </button> </div></div></div></div></script>    <script>
    jQuery(document).ready(function($) {
        console.log('Trip Status JS Loaded'); // Debug no console do navegador
        $('.cancel-trip').on('click', function() {
            var $button = $(this);
            var tripId = $button.data('trip-id');
            var $board = $button.closest('.trip-status-board');
            var $message = $board.find('.trip-status-message');

            // Adiciona campo de motivo dinamicamente
            if (!$board.find('.cancellation-reason').length) {
                $message.html('<p style="color: #856404;">Vamos abrir o WhatsApp para você enviar a solicitação de cancelamento. Cada caso é avaliado individualmente. Se não abrir automaticamente, verifique se o WhatsApp está instalado ou tente novamente.</p>');
                $board.append('<div class="cancellation-reason"><label for="cancel-reason">Motivo do Cancelamento:</label><br><textarea id="cancel-reason" rows="4" style="width:100%; margin-top:5px;"></textarea><br><button class="submit-cancel" data-trip-id="' + tripId + '">Enviar Solicitação</button><button class="cancel-reason">Fechar</button></div>');
                $button.hide(); // Esconde o botão "Cancelar Passeio"
            }
        });

        // Enviar solicitação com motivo
        $(document).on('click', '.submit-cancel', function() {
            var $button = $(this);
            var tripId = $button.data('trip-id');
            var $board = $button.closest('.trip-status-board');
            var $message = $board.find('.trip-status-message');
            var reason = $board.find('#cancel-reason').val().trim();

            if (!reason) {
                $message.html('<p style="color: red;">Por favor, informe o motivo do cancelamento.</p>');
                return;
            }

            var phone = '18294582170';
            var customerName = $board.data('customer-name') || '';
            var customerEmail = $board.data('customer-email') || '';
            var tripName = $board.data('trip-name') || '';
            var startDate = $board.data('start-date') || '';

            var whatsappMessage = '';
            whatsappMessage += '*Solicitação de cancelamento de passeio*\n\n';
            whatsappMessage += '*Cliente:* ' + customerName + (customerEmail ? ' (' + customerEmail + ')' : '') + '\n';
            whatsappMessage += '*ID do passeio (reserva):* ' + tripId + '\n';
            if (tripName) whatsappMessage += '*Passeio:* ' + tripName + '\n';
            if (startDate) whatsappMessage += '*Data:* ' + startDate + '\n';
            whatsappMessage += '\n*Motivo:* ' + reason + '\n';

            var waUrl = 'https://wa.me/' + phone + '?text=' + encodeURIComponent(whatsappMessage);

            var waWindow = window.open('', '_blank');
            if (waWindow) {
                try {
                    waWindow.document.write('Carregando...');
                } catch (e) {}
            }

            $.ajax({
                url: '/wp-admin/admin-ajax.php',
                type: 'POST',
                data: {
                    action: 'mark_cancellation_whatsapp',
                    trip_id: tripId,
                    reason: reason,
                    nonce: '9f622acf31'
                },
                success: function(response) {
                    console.log('AJAX Success:', response);
                    if (response.success) {
                        $message.html('<p style="color: green;">Cancelamento solicitado com sucesso. Vamos abrir o WhatsApp para você enviar a solicitação para nossa equipe.</p>');
                        $board.find('.cancel-trip, .cancellation-reason').remove();
                        $board.find('.booking_status span').html('Cancelamento solicitado').attr('title', 'Cancelamento solicitado').parent().attr('data-colname', 'Status Da Reserva');
                        $board.append('<div class="cancellation-requested-message"><p>Cancelamento não disponível (o passeio já está com Cancelamento solicitado).</p></div>');

                        if (waWindow) {
                            waWindow.location.href = waUrl;
                        } else {
                            window.open(waUrl, '_blank');
                        }
                    } else {
                        if (waWindow) waWindow.close();
                        $message.html('<p style="color: red;">' + response.data + '</p>');
                    }
                },
                error: function(xhr, status, error) {
                    console.error('AJAX Error:', status, error);
                    if (waWindow) waWindow.close();
                    $message.html('<p style="color: red;">Ocorreu um erro ao solicitar o cancelamento. Tente novamente.</p>');
                }
            });

            /*
            // Fluxo antigo (desativado por enquanto): envio via AJAX para aprovação/admin.
            $.ajax({
                url: '/wp-admin/admin-ajax.php',
                type: 'POST',
                data: {
                    action: 'request_cancellation',
                    trip_id: tripId,
                    reason: reason,
                    nonce: '9f622acf31'
                },
                success: function(response) {
                    console.log('AJAX Success:', response); // Debug
                    if (response.success) {
                        $message.html('<p style="color: green;">Sua solicitação de cancelamento foi recebida e será analisada. Nossa equipe entrará em contato em breve.</p>');
                        $board.find('.cancel-trip, .cancellation-reason').remove();
                        $board.find('td.booking_status span').html('Cancelamento solicitado').attr('title', 'Cancelamento solicitado').parent().attr('data-colname', 'Status Da Reserva');
                        
                        // Adiciona mensagem de solicitação feita na parte inferior
                        $board.append('<div class="cancellation-requested-message"><p>Cancelamento não disponível (o passeio já está com Cancelamento solicitado).</p></div>');
                    } else {
                        $message.html('<p style="color: red;">' + response.data + '</p>');
                    }
                },
                error: function(xhr, status, error) {
                    console.error('AJAX Error:', status, error); // Debug
                    $message.html('<p style="color: red;">Ocorreu um erro.</p>');
                }
            });
            */
        });

        // Fechar campo de motivo
        $(document).on('click', '.cancel-reason', function() {
            var $board = $(this).closest('.trip-status-board');
            $board.find('.cancellation-reason').remove();
            $board.find('.trip-status-message').empty();
            $board.find('.cancel-trip').show(); // Reexibe o botão "Cancelar Passeio"
        });
    });
    </script>
